insert into public.articles (id, title, cover, excerpt, body, published, created_at)
values
  ('a_welcome', 'ทำไมพืชต้องการอาหารเสริมทางใบ?', '', 'การให้อาหารทางใบช่วยให้พืชดูดซึมธาตุอาหารได้เร็ว เห็นผลไว เสริมการให้ปุ๋ยทางดิน', 'การให้ธาตุอาหารทางใบ (foliar feeding) เป็นการเสริมธาตุอาหารให้พืชดูดซึมผ่านปากใบได้โดยตรง เห็นผลเร็วกว่าทางดิน เหมาะกับช่วงที่พืชต้องการธาตุอาหารเร่งด่วน เช่น ช่วงเร่งโต ติดดอก หรือบำรุงผล

ควรฉีดพ่นช่วงเช้าหรือเย็นที่อากาศไม่ร้อนจัด และผสมสารจับใบเพื่อให้เกาะติดใบได้ดี ลดการชะล้างจากน้ำค้างหรือฝน', true, 1782384933960),
  ('a_rainy', 'ฉีดพ่นหน้าฝนอย่างไรให้คุ้มค่า', '', 'ฤดูฝนปุ๋ยและยาถูกชะล้างง่าย การใช้สารจับใบช่วยลดการสูญเสียได้มาก', 'ในฤดูฝน น้ำฝนมักชะล้างปุ๋ยและยาที่ฉีดพ่นออกจากใบก่อนพืชจะดูดซึม ทำให้สิ้นเปลือง

การผสม "สารเสริมประสิทธิภาพจับใบ" ช่วยให้ละอองยาเกาะติดผิวใบได้ดีขึ้น ทนต่อการชะล้าง เพิ่มประสิทธิภาพการดูดซึม และลดต้นทุนการฉีดซ้ำ', true, 1782384933960),
  ('a_consult', 'ปรึกษานักวิชาการก่อนเลือกสูตร', '', 'ไม่แน่ใจว่าพืชของคุณควรใช้สูตรไหน? ทักแชทปรึกษาทีมงานได้ฟรี', 'แต่ละช่วงการเจริญเติบโตของพืชต้องการธาตุอาหารต่างกัน การเลือกสูตรให้เหมาะกับชนิดพืชและช่วงอายุจะให้ผลลัพธ์ดีที่สุด

หากไม่แน่ใจ สามารถกดปุ่มแชทมุมขวาล่างเพื่อปรึกษาทีมนักวิชาการของนุชฟอร์ไลฟ์ได้โดยตรง พร้อมแนะนำอัตราการใช้ที่เหมาะกับแปลงของคุณ', true, 1782384933960)
on conflict (id) do update set title = excluded.title, cover = excluded.cover, excerpt = excluded.excerpt, body = excluded.body, published = excluded.published, created_at = excluded.created_at;

